al_amp":"Ashdown amplifier","original_cab":"8x10 cabinet","original_pickup":"Precision Bass split-coil pickup","confidence":73,"era":"1980s"},{"title":"Threshold","artist":"Sungazer","album":"Perihelion","release_year":2021,"mode":"bass","part_type":"bassline","part_label":"main bassline","tone_type":"bass_clean","genre":"jazz fusion","tone_category":"bass","difficulty":"expert","original_guitar":"Fender Jazz Bass (Adam Neely)","original_amp":"Aguilar amplifier","original_cab":"4x10 cabinet","original_pickup":"Jazz Bass single-coil pickups","confidence":71,"era":"2020s"},{"title":"Macchina","artist":"Sungazer","album":"Perihelion","release_year":2021,"mode":"bass","part_type":"bassline","part_label":"main bassline","tone_type":"bass_clean","genre":"jazz fusion","tone_category":"bass","difficulty":"expert","original_guitar":"Fender Jazz Bass (Adam Neely)","original_amp":"Aguilar amplifier","original_cab":"4x10 cabinet","original_pickup":"Jazz Bass single-coil pickups","confidence":69,"era":"2020s"},{"title":"Lunar","artist":"Sungazer","album":"Perihelion","release_year":2021,"mode":"bass","part_type":"bassline","part_label":"main bassline","tone_type":"bass_clean","genre":"jazz fusion","tone_category":"bass","difficulty":"expert","original_guitar":"Fender Jazz Bass (Adam Neely)","original_amp":"Aguilar amplifier","original_cab":"4x10 cabinet","original_pickup":"Jazz Bass single-coil pickups","confidence":68,"era":"2020s"},{"title":"A Song With No Words","artist":"Sungazer","album":"Perihelion","release_year":2021,"mode":"bass","part_type":"bassline","part_label":"main bassline","tone_type":"bass_clean","genre":"jazz fusion","tone_category":"bass","difficulty":"expert","original_guitar":"Fender Jazz Bass (Adam Neely)","original_amp":"Aguilar amplifier","original_cab":"4x10 cabinet","original_pickup":"Jazz Bass single-coil pickups","confidence":67,"era":"2020s"},{"title":"Cytherean","artist":"Sungazer","album":"Perihelion","release_year":2021,"mode":"bass","part_type":